#include <iostream>
#include <vector>
#include <fstream>
#include <stdexcept>
#include <chrono>
#include <cmath>

// Макросы для обработки ошибок CUDA
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            throw std::runtime_error(std::string("CUDA Error: ") + cudaGetErrorString(err)); \
        } \
    } while (0)

// Типы данных
using IndexType = int;
using DataType = float;

class KNNGraphWrapper {
private:
    // Параметры
    int n_points;
    int k_neighbors;
    int dim;
    bool is_built;
    bool debug_mode;

    // Указатели на память GPU
    DataType* d_data;      // Входные данные (N x dim)
    IndexType* d_graph;    // Граф KNN (N x K) - индексы соседей
    DataType* d_distances; // Расстояния (опционально, для отладки/уточнения)

    // Вспомогательные функции
    void check_cuda_error(const char* msg);
    void print_debug_info(const std::string& stage);

public:
    // Конструктор
    KNNGraphWrapper(int n, int k, int d, bool debug = false);

    // Деструктор (очистка GPU памяти)
    ~KNNGraphWrapper();

    // 1. Загрузка набора данных
    void loadData(const DataType* h_data);

    // 2. Построение графа KNN (Заглушка для ядра CUDA)
    void buildGraph();

    // 3. Уточнение графа (Refinement) - например, добавление обратных связей
    void refineGraph();

    // 4. Генерация эталонных данных (для оценки)
    void generateGroundTruth(const DataType* h_data);

    // 5. Оценка графа (Recall@K, Precision и т.д.)
    void evaluateGraph(const IndexType* h_ground_truth);

    // 6. Операции запросов
    void query(const DataType* h_query_points, int n_queries, IndexType* h_results);

    // 7. Сериализация: Запись графа
    void saveGraph(const std::string& filename);

    // 8. Сериализация: Чтение графа
    void loadGraph(const std::string& filename);

    // 9. Сброс графа для подмножества
    void resetSubset(int subset_size);

    // Геттеры
    int getN() const { return n_points; }
    int getK() const { return k_neighbors; }
    bool isBuilt() const { return is_built; }
};

// --- Реализация методов ---

KNNGraphWrapper::KNNGraphWrapper(int n, int k, int d, bool debug) 
    : n_points(n), k_neighbors(k), dim(d), is_built(false), debug_mode(debug),
      d_data(nullptr), d_graph(nullptr), d_distances(nullptr) {

    if (n <= 0 || k <= 0 || d <= 0) {
        throw std::invalid_argument("Размеры должны быть положительными.");
    }

    // Выделение памяти на GPU
    size_t data_size = static_cast<size_t>(n_points) * dim * sizeof(DataType);
    size_t graph_size = static_cast<size_t>(n_points) * k_neighbors * sizeof(IndexType);

    CUDA_CHECK(cudaMalloc(&d_data, data_size));
    CUDA_CHECK(cudaMalloc(&d_graph, graph_size));

    // Инициализация графа нулями
    CUDA_CHECK(cudaMemset(d_graph, 0, graph_size));

    if (debug_mode) {
        std::cout << "[Init] GPU memory allocated for " << n_points << " points, K=" << k_neighbors << "\n";
    }
}

KNNGraphWrapper::~KNNGraphWrapper() {
    if (d_data) cudaFree(d_data);
    if (d_graph) cudaFree(d_graph);
    if (d_distances) cudaFree(d_distances);
}

void KNNGraphWrapper::loadData(const DataType* h_data) {
    size_t data_size = static_cast<size_t>(n_points) * dim * sizeof(DataType);
    CUDA_CHECK(cudaMemcpy(d_data, h_data, data_size, cudaMemcpyHostToDevice));
    if (debug_mode) print_debug_info("Data loaded to GPU");
}

// Ядро CUDA для наивного построения KNN (пример)
__global__ void buildKNNKernel(const DataType* data, IndexType* graph, int n, int k, int dim) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    // Простой перебор (для демонстрации, в реальности нужен более сложный алгоритм)
    // Здесь мы просто заполняем граф индексами 0..k-1 для примера
    // В реальном коде здесь будет вычисление расстояний и поиск минимума
    for (int j = 0; j < k; ++j) {
        graph[idx * k + j] = (idx + j + 1) % n; 
    }
}

void KNNGraphWrapper::buildGraph() {
    if (debug_mode) std::cout << "[Build] Starting graph construction...\n";

    int threads = 256;
    int blocks = (n_points + threads - 1) / threads;

    buildKNNKernel<<<blocks, threads>>>(d_data, d_graph, n_points, k_neighbors, dim);
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    is_built = true;
    if (debug_mode) print_debug_info("Graph built");
}

void KNNGraphWrapper::refineGraph() {
    if (!is_built) throw std::runtime_error("Graph must be built before refinement.");
    if (debug_mode) std::cout << "[Refine] Refining graph structure...\n";

    // Здесь можно реализовать ядро для добавления обратных связей (Symmetrization)
    // Пример: если A -> B, то добавить B -> A
    // Реализация зависит от конкретного алгоритма уточнения
    if (debug_mode) print_debug_info("Graph refined");
}

void KNNGraphWrapper::generateGroundTruth(const DataType* h_data) {
    // В реальном сценарии это может быть запуск точного алгоритма на CPU или GPU
    // для создания эталона, который затем сравнивается с d_graph
    if (debug_mode) std::cout << "[GT] Generating ground truth (simulated)...\n";
}

void KNNGraphWrapper::evaluateGraph(const IndexType* h_ground_truth) {
    if (!is_built) throw std::runtime_error("Graph not built.");

    // Копирование графа на CPU для оценки
    size_t graph_size = static_cast<size_t>(n_points) * k_neighbors * sizeof(IndexType);
    std::vector<IndexType> h_graph(n_points * k_neighbors);
    CUDA_CHECK(cudaMemcpy(h_graph.data(), d_graph, graph_size, cudaMemcpyDeviceToHost));

    int correct = 0;
    for (int i = 0; i < n_points; ++i) {
        for (int j = 0; j < k_neighbors; ++j) {
            if (h_graph[i * k_neighbors + j] == h_ground_truth[i * k_neighbors + j]) {
                correct++;
            }
        }
    }

    double recall = static_cast<double>(correct) / (n_points * k_neighbors);
    std::cout << "[Eval] Recall@K: " << recall << "\n";
}

void KNNGraphWrapper::query(const DataType* h_query_points, int n_queries, IndexType* h_results) {
    if (!is_built) throw std::runtime_error("Graph not built.");

    // В реальном приложении здесь будет ядро CUDA для обхода графа (например, Greedy Search)
    // Для примера просто копируем данные, предполагая, что ядро queryKernel заполнит h_results
    // Но так как h_results на хосте, нам нужно сначала скопировать query в GPU, выполнить ядро, потом обратно.

    // Заглушка: предположим, что мы ищем соседей для query_points в d_data
    // Реализация ядра поиска пропущена для краткости
    std::cout << "[Query] Executing " << n_queries << " queries...\n";

    // Здесь должен быть вызов: queryKernel<<<...>>>(d_data, d_graph, d_query, h_results, ...);
    // Для демонстрации заполним результаты нулями
    std::fill(h_results, h_results + n_queries * k_neighbors, -1);
}

void KNNGraphWrapper::saveGraph(const std::string& filename) {
    if (!is_built) throw std::runtime_error("Cannot save: graph not built.");

    std::ofstream file(filename, std::ios::binary);
    if (!file) throw std::runtime_error("Failed to open file for writing: " + filename);

    // Заголовок
    file.write(reinterpret_cast<const char*>(&n_points), sizeof(int));
    file.write(reinterpret_cast<const char*>(&k_neighbors), sizeof(int));
    file.write(reinterpret_cast<const char*>(&dim), sizeof(int));

    // Данные графа
    size_t graph_size = static_cast<size_t>(n_points) * k_neighbors * sizeof(IndexType);
    std::vector<IndexType> h_graph(n_points * k_neighbors);
    CUDA_CHECK(cudaMemcpy(h_graph.data(), d_graph, graph_size, cudaMemcpyDeviceToHost));

    file.write(reinterpret_cast<const char*>(h_graph.data()), graph_size);
    file.close();

    if (debug_mode) std::cout << "[IO] Graph saved to " << filename << "\n";
}

void KNNGraphWrapper::loadGraph(const std::string& filename) {
    std::ifstream file(filename, std::ios::binary);
    if (!file) throw std::runtime_error("Failed to open file for reading: " + filename);

    int n, k, d;
    file.read(reinterpret_cast<char*>(&n), sizeof(int));
    file.read(reinterpret_cast<char*>(&k), sizeof(int));
    file.read(reinterpret_cast<char*>(&d), sizeof(int));

    if (n != n_points || k != k_neighbors || d != dim) {
        throw std::runtime_error("File dimensions mismatch with current wrapper configuration.");
    }

    size_t graph_size = static_cast<size_t>(n_points) * k_neighbors * sizeof(IndexType);
    std::vector<IndexType> h_graph(n_points * k_neighbors);
    file.read(reinterpret_cast<char*>(h_graph.data()), graph_size);
    file.close();

    CUDA_CHECK(cudaMemcpy(d_graph, h_graph.data(), graph_size, cudaMemcpyHostToDevice));
    is_built = true;

    if (debug_mode) std::cout << "[IO] Graph loaded from " << filename << "\n";
}

void KNNGraphWrapper::resetSubset(int subset_size) {
    if (subset_size <= 0 || subset_size > n_points) {
        throw std::invalid_argument("Invalid subset size.");
    }

    // Сброс графа для первых subset_size точек
    size_t subset_graph_size = static_cast<size_t>(subset_size) * k_neighbors * sizeof(IndexType);
    CUDA_CHECK(cudaMemset(d_graph, 0, subset_graph_size));

    if (debug_mode) std::cout << "[Reset] Graph reset for subset size: " << subset_size << "\n";
}

void KNNGraphWrapper::check_cuda_error(const char* msg) {
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        std::cerr << "CUDA Error at " << msg << ": " << cudaGetErrorString(err) << std::endl;
    }
}

void KNNGraphWrapper::print_debug_info(const std::string& stage) {
    std::cout << "[DEBUG][" << stage << "] Time: " 
              << std::chrono::duration_cast<std::chrono::milliseconds>(
                     std::chrono::high_resolution_clock::now().time_since_epoch()).count() 
              << " ms\n";
}

// --- Пример использования (main) ---
int main() {
    try {
        int N = 10000;
        int K = 10;
        int D = 128;
        bool debug = true;

        KNNGraphWrapper knn(N, K, D, debug);

        // Генерация случайных данных на CPU
        std::vector<float> h_data(N * D);
        for (int i = 0; i < N * D; ++i) {
            h_data[i] = static_cast<float>(rand()) / RAND_MAX;
        }

        // 1. Загрузка
        knn.loadData(h_data.data());

        // 2. Построение
        knn.buildGraph();

        // 3. Уточнение
        knn.refineGraph();

        // 4. Сохранение
        knn.saveGraph("knn_graph.bin");

        // 5. Сброс подмножества (например, для инкрементального обновления)
        knn.resetSubset(1000);

        // 6. Запросы (заглушка)
        std::vector<float> h_query(100 * D);
        std::vector<int> h_results(100 * K);
        knn.query(h_query.data(), 100, h_results.data());

        std::cout << "All operations completed successfully.\n";

    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
```

### Ключевые особенности реализации

1.  **Гибкость и безопасность**:
    *   Используется `std::vector` для временных буферов на хосте.
    *   Все вызовы CUDA обернуты в макрос `CUDA_CHECK`, который выбрасывает исключение при ошибке, что упрощает отладку.
    *   Деструктор автоматически освобождает память GPU.

2.  **Модульность**:
    *   Логика построения, уточнения и запросов вынесена в отдельные методы.
    *   Ядра CUDA (`__global__`) объявлены отдельно, что позволяет легко заменять их на более сложные алгоритмы (например, используя библиотеку `cuML` или `FAISS` внутри этих методов).

3.  **Функциональность**:
    *   **Сериализация**: Методы `saveGraph` и `loadGraph` сохраняют бинарный файл с заголовком (размеры) и данными графа.
    *   **Сброс подмножества**: `resetSubset` позволяет очистить часть графа, что полезно для инкрементального обучения или тестирования.
    *   **Отладка**: Флаг `debug_mode` включает вывод временных меток и статусов операций.

4.  **Расширяемость**:
    *   В методе `buildGraph` сейчас стоит заглушка. Для реального использования замените вызов `buildKNNKernel` на ядро, реализующее алгоритм (например, IVF-PQ, HNSW или наивный перебор с оптимизациями).
    *   Метод `query` также требует реализации ядра поиска по графу (например, Greedy Search для HNSW).

