Ниже представлен пример реализации метода `build` на языке **Go**, который соответствует вашим требованиям. Этот код использует стандартную библиотеку `net/http` и типичные паттерны для построения HTTP-клиентов с настройкой прокси, TLS, аутентификации и тайм-аутов.

В примере предполагается, что структура `TransportBuilder` уже содержит поля для хранения настроек, а тип `Transport` — это интерфейс или структура, оборачивающая `http.Client` (или сам `http.Transport`), специфичная для вашего проекта.

### Реализация на Go

```go
package elasticsearch

import (
	"crypto/tls"
	"crypto/x509"
	"fmt"
	"net/http"
	"net/url"
	"os"
	"time"
)

// TransportBuilder хранит конфигурацию для построения транспорта
type TransportBuilder struct {
	// Прокси
	proxyURL       *url.URL
	proxyUser      string
	proxyPassword  string
	disableProxy   bool // Если true, игнорируем системные прокси и кастомные настройки

	// Аутентификация клиента (Basic Auth для Elasticsearch)
	clientUser     string
	clientPassword string

	// TLS / Сертификаты
	caCertPath     string // Путь к файлу CA сертификата
	insecure       bool   // Если true, отключаем проверку сертификата (не рекомендуется для продакшена)

	// Заголовки
	headers        map[string]string

	// Тайм-аут
	timeout        time.Duration
}

// Transport представляет собой готовый HTTP-клиент для работы с Elasticsearch
type Transport struct {
	Client *http.Client
}

// Build создает и возвращает настроенный Transport
func (tb *TransportBuilder) Build() (*Transport, error) {
	// 1. Настройка Transport (основа HTTP-клиента)
	transport := &http.Transport{
		// По умолчанию используем системный прокси, если не отключено
		Proxy: http.ProxyFromEnvironment,
	}

	// 2. Настройка прокси
	if tb.disableProxy {
		// Явно отключаем прокси, возвращая nil
		transport.Proxy = nil
	} else if tb.proxyURL != nil {
		// Если задан кастомный прокси, настраиваем его
		proxyFunc := func(req *http.Request) (*url.URL, error) {
			// Если есть учетные данные для прокси, добавляем их в URL
			if tb.proxyUser != "" || tb.proxyPassword != "" {
				tb.proxyURL.User = url.UserPassword(tb.proxyUser, tb.proxyPassword)
			}
			return tb.proxyURL, nil
		}
		transport.Proxy = proxyFunc
	}

	// 3. Настройка TLS (HTTPS)
	tlsConfig := &tls.Config{
		MinVersion: tls.VersionTLS12, // Рекомендуется минимум TLS 1.2
	}

	if tb.insecure {
		// Внимание: отключение проверки сертификата небезопасно для продакшена
		tlsConfig.InsecureSkipVerify = true
	} else if tb.caCertPath != "" {
		// Загрузка и проверка CA сертификата
		caCert, err := os.ReadFile(tb.caCertPath)
		if err != nil {
			return nil, fmt.Errorf("не удалось прочитать CA сертификат: %w", err)
		}

		caCertPool := x509.NewCertPool()
		if !caCertPool.AppendCertsFromPEM(caCert) {
			return nil, fmt.Errorf("не удалось добавить CA сертификат в пул")
		}

		tlsConfig.RootCAs = caCertPool
	}

	transport.TLSClientConfig = tlsConfig

	// 4. Создание HTTP-клиента
	client := &http.Client{
		Transport: transport,
	}

	// 5. Установка глобального тайм-аута
	if tb.timeout > 0 {
		client.Timeout = tb.timeout
	}

	// 6. Добавление базовой аутентификации (если задана)
	// Мы можем добавить это через RoundTripper или просто в заголовки при каждом запросе.
	// Для простоты здесь мы создадим обертку RoundTripper, которая добавляет заголовки.
	if tb.clientUser != "" || tb.clientPassword != "" {
		client.Transport = &authRoundTripper{
			transport: client.Transport,
			user:      tb.clientUser,
			pass:      tb.clientPassword,
		}
	}

	// 7. Добавление глобальных заголовков
	if len(tb.headers) > 0 {
		client.Transport = &headerRoundTripper{
			transport: client.Transport,
			headers:   tb.headers,
		}
	}

	return &Transport{Client: client}, nil
}

// authRoundTripper добавляет Basic Auth заголовок ко всем запросам
type authRoundTripper struct {
	transport http.RoundTripper
	user      string
	pass      string
}

func (rt *authRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
	req.SetBasicAuth(rt.user, rt.pass)
	return rt.transport.RoundTrip(req)
}

// headerRoundTripper добавляет пользовательские заголовки ко всем запросам
type headerRoundTripper struct {
	transport http.RoundTripper
	headers   map[string]string
}

func (rt *headerRoundTripper) RoundTrip(req *http.Request) (*http.Response, error) {
	for k, v := range rt.headers {
		req.Header.Set(k, v)
	}
	return rt.transport.RoundTrip(req)
}
```

### Ключевые особенности реализации:

1.  **Прокси и его отключение**:
    *   По умолчанию используется `http.ProxyFromEnvironment` (системные переменные `HTTP_PROXY` и т.д.).
    *   Если `disableProxy` установлен в `true`, прокси принудительно отключается (`transport.Proxy = nil`).
    *   Если задан `proxyURL`, создается функция прокси, которая добавляет базовую аутентификацию (имя пользователя/пароль) прямо в URL прокси, если они указаны.

2.  **Аутентификация клиента (Elasticsearch)**:
    *   Реализована через кастомный `RoundTripper` (`authRoundTripper`). Это позволяет автоматически добавлять заголовок `Authorization: Basic ...` ко всем исходящим запросам без необходимости менять код вызова API.

3.  **Проверка сертификатов (TLS)**:
    *   Если указан путь к CA-сертификату (`caCertPath`), он загружается и добавляется в пул доверенных сертификатов (`RootCAs`).
    *   Если флаг `insecure` включен, проверка сертификата отключается (`InsecureSkipVerify = true`).

4.  **Глобальные заголовки**:
    *   Реализована обертка `headerRoundTripper`, которая добавляет все ключ-значение из карты `headers` к каждому запросу.

5.  **Тайм-аут**:
    *   Устанавливается в поле `Timeout` объекта `http.Client`, что ограничивает общее время ожидания ответа (включая подключение и чтение).

6.  **Безопасность и ошибки**:
    *   Метод возвращает ошибку, если не удается прочитать файл сертификата или добавить его в пул.
    *   Используется `MinVersion: tls.VersionTLS12` для обеспечения минимального уровня безопасности.

Этот метод `Build` возвращает готовый к использованию объект `Transport`, который можно передать в клиент Elasticsearch (например, в `elasticsearch.NewClient` из официального клиента Go, если он принимает `http.Client`, или использовать напрямую для выполнения запросов).

